  piece.dataset.locked = "false";
  piece.style.width = "".concat(PIECE_SIZE, "rem");
  piece.style.height = "".concat(PIECE_SIZE, "rem");
  piece.style.backgroundImage = "url(\"".concat(jigsaw_namespaceObject, "\")");
  piece.style.backgroundSize = "".concat(BOARD_SIZE, "rem ").concat(BOARD_SIZE, "rem");
